compliant:
public class WebHelper
{
    public void Navigate(string uri)  // Compliant - calls Uri overload
    {
        Navigate(new Uri(uri));
    }

    public void Navigate(Uri uri)
    {
        var client = new HttpClient();
        client.GetAsync(uri);
    }
}
